var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"야, 노엘…! 정신 차려……!","JPN":"ノエル……！　しっかりして……！","ENG":"Hey, Noelle...! Snap out of it...!","TWN":"喂，洛艾兒！振作點！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 왔어! 내가 널 구하러 왔단 말이야……!","JPN":"私が来た！　あなたを助けに来たんだよ……！","ENG":"I'm here! I came to save you...!","TWN":"我來了！我是來救你的！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 멍하니 있지 말고, 빨리 정신 차리라고……!","JPN":"だからぼーっとしてないで、早く正気に戻って……！","ENG":"So don't just sit there, wake up already...!","TWN":"所以，不要發呆，趕快振作起來！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"큭, 제기랄……!","JPN":"くっ、こんな……！","ENG":"Kgh, damn it...!","TWN":"呃，該死！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 짓이야, 스완! 노엘한테서 떨어져!","JPN":"何をするの、スワン！　ノエルから離れろ！","ENG":"What are you doing, Swan?! Get away from Noelle!","TWN":"你在幹什麼？史旺！離洛艾兒遠點！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇게 애타게 불러봐도 소용없답니다, 늑대.","JPN":"どれだけ懸命に呼びかけたって無駄です、オオカミ。","ENG":"You can cry out all you want, but it's useless, Wolf.","TWN":"就算你再怎麼焦急地呼喚也沒用，狼。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 이 아이는 이미 정신이 망가져, 자아를 상실해 버렸으니까요.","JPN":"なぜならこの子はすでに精神が崩壊し、自我を失っていますから。","ENG":"Because this girl's mind is already shattered. She's lost all sense of self.","TWN":"因為這個孩子的精神已經崩潰，失去了自我。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이래서야 인간이 아니라, 곱상한 인형에 불과하군요.","JPN":"ふふ、これでは人間ではなく、ただの愛らしいお人形ですね。","ENG":"Haha, she's not human anymore. Just a pretty little doll.","TWN":"呵呵，這樣的話，不是人類，只不過是個漂亮的玩偶而已。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 살결이 제법 부드럽네요. 제 취향은 아니지만, 어디 조금은 가지고 놀아볼까요?","JPN":"まあ、なんて柔らかい肌。私の好みではないけれど、少しくらい遊んでみましょうか。","ENG":"Haha, her skin's soft. Not really my type, but maybe I'll play with her for a bit?","TWN":"呵呵，肌膚還挺柔軟的嘛。雖然不是我的菜，但要不要稍微玩玩呢？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"젠장, 그만둬! 그만두라고……!!","JPN":"くそ、やめろ！　やめろってば……！！","ENG":"Damn it, stop! I said stop...!!","TWN":"該死，住手！住手！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보기보다 학습 능력이 없네요, 늑대. 소용없다고 했을 텐데요?","JPN":"案外学習能力が乏しいのですね、オオカミ。無駄だと言ったはずです。","ENG":"You really don't learn, do you, Wolf? I told you it's pointless.","TWN":"看起來你的學習能力不怎麼樣，狼。我不是說過沒用嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 모습도, 목소리도 결코 이 아이에게 닿지 않는답니다.","JPN":"あなたの姿も、声も、決してこの子に届くことはありません。","ENG":"Your face, your voice. None of it will ever reach her.","TWN":"無論是你的樣子，還是聲音，都無法傳達到這個孩子那裡。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 아이는 그저 제가 머릿속에 심어둔 각본대로 이 세계를 재현하고 있을 뿐이니까요.","JPN":"この子はただ、私が頭の中に植え付けておいた脚本どおりにこの世界を再現しているだけですから。","ENG":"She's simply playing out the script I planted in her mind. Recreating this world exactly as I wrote it.","TWN":"這個孩子只是在按照我在她腦海中植入的劇本，重現這個世界而已。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 이제 곧, 이 세계가 멸망하는 순간을 그대로 재현해 내겠죠.","JPN":"そして間もなく、この世界が滅亡する瞬間をそのまま再現するでしょう。","ENG":"And soon, she'll recreate the moment this world meets its end.","TWN":"而現在，她將重現這個世界毀滅的瞬間。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 순간이 바로 이번 각본이 엔딩을 맞이하는 시점입니다.","JPN":"その瞬間こそが、今回の脚本のエンディングなのです。","ENG":"That moment will mark the end of this script.","TWN":"那個時刻正是這次劇本迎來結局的時刻。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"세계가 멸망하는 순간을 재현하겠다고……?","JPN":"世界が滅亡する瞬間を再現する……？","ENG":"Recreate the end of the world...?","TWN":"要重現世界毀滅的瞬間？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마……!","JPN":"まさか……！","ENG":"No way...!","TWN":"不會吧！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"젠장, 어째 시간을 끌고 있는 것 같더니만……!","JPN":"ちっ、なんか時間稼ぎしてるなと思ったら……！","ENG":"Damn it, so that's why you were stalling for time...!","TWN":"可惡，我說怎麼總感覺她在拖延時間！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시간을 끌어? 그게 무슨 소리야?","JPN":"時間稼ぎ？　どういうこと？","ENG":"Stalling? What do you mean?","TWN":"拖延時間？什麼意思？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 짐작한 대로라네, 미나 양.","JPN":"君の予測通りだよ、ミナ君。","ENG":"Just as you suspect, Mina.","TWN":"正如你所猜測的那樣，米娜。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완은 이 세계를 또다시 <color=#ffd34c>되풀이</color>할 생각이라네.","JPN":"スワンはまたしても、この世界を<color=#ffd34c>繰り返す</color>つもりだ。","ENG":"Swan intends to <color=#ffd34c>repeat</color> this world all over again.","TWN":"史旺打算再次<color=#ffd34c>重複</color>這個世界。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"되풀이라고?","JPN":"繰り返す？","ENG":"Repeat it?","TWN":"重複？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 아마도 몇 번이고… 몇 번이고…….","JPN":"ああ。おそらく何回も……何回も……","ENG":"Yes. Over and over... and over again...","TWN":"是的。可能是好幾次……好多次……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자신이 원하는 결과에 다다를 때까지, 세계의 멸망을 계속해서 반복할 셈이겠지.","JPN":"自分の望む結果に至るまで、世界の滅亡を繰り返すのだろう。","ENG":"Until she gets the result she wants, she'll keep repeating the world's destruction.","TWN":"看來你打算不斷重複世界的毀滅，直到達到你想要的結果為止。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"원하는 결과라고…? 웃기지 마……!","JPN":"望む結果だって……？　ふざけないで……！","ENG":"The result she wants...? You've got to be kidding...!","TWN":"你說這是你想要的結果？開什麼玩笑！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"되돌린 고향 세계를 제 손으로 부숴가면서, 자기가 아는 사람들을 전부 죽여가면서……!","JPN":"戻した故郷の世界を自らの手で壊して、自分の知る人間を全員殺して……！","ENG":"She wrecked her own home world with her own hands, killed everyone she ever knew...!","TWN":"親手摧毀重現的故鄉世界，殺掉所有認識的人！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘까지 저렇게 만들어 놓고… 대체 그 원하는 결과라는 게 뭔데……!!","JPN":"ノエルまであんなにして……その望む結果っていったい何だよ……！！","ENG":"And did that to Noelle... Just what is it that she wants...?!","TWN":"把洛艾兒也弄成那樣……到底你想要的結果是什麼？？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"늑대, 당신은 상냥한 사람이로군요.","JPN":"オオカミ、あなたは優しいのね。","ENG":"You're such a kind person, Wolf.","TWN":"狼，你是個溫柔的人。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설마 이곳, 도시 하나짜리 세계와 이곳의 모든 사람이 정말로 진짜라고 생각하는 건가요?","JPN":"まさか、この都市一つだけの世界とここにいる人たちが、本当に実在すると信じているのですか？","ENG":"Do you really think this one-city world and everyone in it is real?","TWN":"難道你真的認為這個地方，這個城市大小的世界和這裡的所有人都是真實的嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"え……？","ENG":"What...?","TWN":"你說什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"일반인? 너야 말로 무슨 착각을 하는 거야, 유미나?","JPN":"一般人？　あんたこそ、勘違いしてるんじゃない？　ヤナギ・ミナ。","ENG":"Civilians? Don't you think you're the one who's confused here, Yoo Mina?","TWN":"普通人？你才是搞錯了什麼，劉米娜？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너는 진심으로 저 자식들이 우리와 같은 사람이라고 생각해?","JPN":"本気で、あいつらがあたしたちと同じく人間だと思ってんの？","ENG":"Do you honestly think those jerks are just like us?","TWN":"你真的認為那些傢伙和我們是一樣的嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"No way...","TWN":"難道？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 세계와 이곳에 속한 이들은 세피라와 제 기억을 통해, 재창조된 허구에 불과합니다.","JPN":"この世界とここに属する者たちは、セフィラと私の記憶から再創造された作り物に過ぎません。","ENG":"This world and everyone in it were recreated from Sephira and my memories. They're just fiction.","TWN":"這個世界和屬於這裡的人們，只是通過世界樹和我的記憶重新創造的虛構產物。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그마저도 제가 경험하지 못했던 부분은 재구성할 수 없는 불완전한 세계라고 할 수 있죠.","JPN":"しかも私が経験できなかった部分は再構成できない、不完全な世界です。","ENG":"And even then, the parts I never experienced couldn't be reconstructed. It's an incomplete world.","TWN":"最起碼那些我未曾經歷的部分是無法重構的。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 당신은 만들어진 허구를 동정할 셈인가요?","JPN":"それでもあなたは、作られた虚構に同情しますか？","ENG":"And yet, you still pity this fabricated fiction?","TWN":"即便如此，你也打算同情被創造出來的虛構之物嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무엇이든 탄생하려는 자는 하나의 세계를 부숴야 한다는 말이 있죠.","JPN":"生まれようとする者は、まず1つの世界を壊す必要があると言いますね。","ENG":"There's a saying that for something new to be born, an old world must first be destroyed.","TWN":"據說，任何想要誕生的事物都必須打破一個世界。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 이 손으로 여러 세계를 무너트려 왔습니다. 그러니 고향 세계 또한 예외는 아니에요.","JPN":"私はこの手で、数多くの世界を滅ぼしてきました。故郷の世界といえど、例外ではありません。","ENG":"I've already destroyed countless worlds with these hands. My home world is no exception.","TWN":"我用這雙手摧毀了多個世界，故鄉的世界也不例外。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하는 것을 이루기 위해서라면, 몇 번이든 이곳 런던을 부술 수 있죠.","JPN":"私の望みを叶えるためなら、何度だってこのロンドンを壊しましょう。","ENG":"If it means getting what I want, I'll destroy this London as many times as it takes.","TWN":"為了實現我的願望，我可以無數次摧毀這座倫敦。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 무슨……!","JPN":"なにそれ……！","ENG":"What...?!","TWN":"那是什麼……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 짓을 해서 무슨 의미가 있다는 거야……!?","JPN":"そんなことをして、何の意味があるの……！","ENG":"What's even the point of doing all that...?!","TWN":"做那種事有什麼意義！？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하는 것은 이 땅에 진정한 <color=#ffd34c>천사</color>를 강림시키는 것.","JPN":"私の望み、それはこの地に真の<color=#ffd34c>天使</color>を降臨させること。","ENG":"What I want is to summon a true <color=#ffd34c>angel</color> to this land.","TWN":"我想要的是讓真正的<color=#ffd34c>天使</color>降臨到這片土地上。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 아이의 힘은 아직 불안정하답니다.","JPN":"この子の力はまだ不安定です。","ENG":"This child's power is still unstable.","TWN":"這個孩子的力量還不穩定。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 이 아이 안에 잠들어 있는 세피라 신성 에너지… 그건 순수한 형태의 가능성이에요.","JPN":"ですが、この子の中に眠っているセフィラの神聖エネルギー……。それは純粋な形の可能性です。","ENG":"But the Sephira Divinity energy slumbering within her... it's a pure form of possibility.","TWN":"但是這個孩子體內沉睡的生命樹神聖能量……那是純粹形態的可能性。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 가능성이라면… 세계의 끝을 너머 시작으로, 불완전한 세계를 완전한 세계로…….","JPN":"その可能性があれば……世界の終わりを超えて始まりへ、不完全な世界を完全なる世界へと……","ENG":"And that possibility... might just carry us beyond the end toward a new beginning. From an imperfect world to a perfect one...","TWN":"有那種可能性的話……可以將世界的盡頭到開始，將不完整的世界變為完整的世界……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어쩌면 제 기억마저 초월하여, 모든 이야기를 처음으로 되돌리는 것조차 가능할지도 모르죠.","JPN":"もしかすると私の記憶さえも超越して、全ての物語を振り出しに戻すことすら可能かもしれません。","ENG":"Maybe it could even surpass my memories and revert all the stories to their beginning.","TWN":"甚至可以超越我的記憶，讓整個故事回到起點。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"모든 이야기를 처음으로 되돌린다고?","JPN":"全ての物語を振り出しに戻すって？","ENG":"Revert all the stories to their beginning?","TWN":"要把所有故事都回到起點嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 정말로 멸망해 버린 세계를 되돌리는 게 가능하단 말이야……?","JPN":"じゃあ、本当に滅亡した世界を元に戻すことが可能なの……？","ENG":"You mean it's actually possible to bring back a world that was completely destroyed...?","TWN":"真的有可能讓已經毀滅的世界恢復原狀嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 무모한 이야기야, 아이린!","JPN":"それは無謀な話だ、アイリーン！","ENG":"That's madness, Irene!","TWN":"那是個魯莽的事，愛琳！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마가 저질렀던 천사 강림 의식은 그저 엉터리 의식에 불과해!","JPN":"深夜の殺人鬼が行った天使降臨の儀式は、ただのデタラメに過ぎない！","ENG":"The angel summoning ritual committed by the Midnight Killer was just a farce!","TWN":"午夜殺人魔所進行的天使降臨儀式不過是個荒唐的儀式而已！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하물며 천사라는 것이 존재한다고 해도, 정말 자네가 원하는 것을 이루어 줄 수 있을까?","JPN":"仮に天使というものが存在したとして、それが本当に君の望みを叶えられるのかね？","ENG":"Even if angels were real, would they really give you what you want?","TWN":"即便天使真的存在，真的能實現你的願望嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 한번 생각해 보게……!","JPN":"もう一度考えてみたまえ……！","ENG":"Please reconsider...!","TWN":"再好好考慮一下吧！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 세피라라는 힘이 정확히 어떤 식으로 현실에 작용하는지는 모르겠지만…….","JPN":"そのセフィラという力が、具体的にどういう風に現実に作用するのかは知らないが……","ENG":"I don't know exactly how the power of Sephira affects reality...","TWN":"雖然不知道那叫做生命樹的力量究竟是如何作於于現實的……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 자네의 기억을 재구성하는 우회적인 방법으로 세계를 되돌려 놓을 수 있었어.","JPN":"君は、君の記憶を再構成するという遠回りなやり方で世界を元に戻すことに成功した。","ENG":"But you've used it to reconstruct your memories and rewind the world indirectly.","TWN":"你通過重構自己的記憶，以一種迂回的方式將世界恢復了原狀。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아마도 그건 망각의 여신으로부터 미움받는 자네이기에 떠올릴 수 있는 발상이었겠지.","JPN":"おそらくそれは、忘却の女神に愛されなかった君だからこそできた発想だったのだろう。","ENG":"Maybe that's something only you, hated by the goddess of oblivion, could've come up with.","TWN":"也許那是因為你是被遺忘女神所詛咒的人，才能想到這樣的主意吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그렇다고 해도 기억의 당사자인 자네 자신은 과거로 돌아갈 수 없었어.","JPN":"しかし、記憶の当事者である君自身が過去に戻れたわけではなかった。","ENG":"But even so, you yourself couldn't return to the past.","TWN":"但即便如此，作為記憶的主人的你自己也沒能回到過去。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 증거로 이 세계에는 자네가 두 사람 존재하게 되지 않았나?","JPN":"その証拠として、この世界には君が2人存在しているだろう？","ENG":"If you could, why are there two of you in this world?","TWN":"這個世界上還有兩個你存在，這就是證據不是嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니…….","JPN":"言われてみれば……","ENG":"Now that you mention it...","TWN":"這麼說來……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인…….","JPN":"アバーライン……","ENG":"Abberline...","TWN":"艾伯林……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 재밌군요.","JPN":"ふふ、面白いですね。","ENG":"Haha, how amusing.","TWN":"呵呵，真有趣啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 그게 뭐 어쨌다는 거죠?","JPN":"それで？　それがどうしたと言うのですか？","ENG":"And what of it?","TWN":"所以那又怎麼樣呢？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"기억을 초월하여, 모든 이야기를 처음으로 되돌리겠다고?","JPN":"記憶を超越して、全ての物語を振り出しに戻すと言ったね？","ENG":"You want to transcend memory and revert all the stories to their beginning?","TWN":"你想超越記憶，要將整個故事回到起點嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 되돌리더라도, 자네가 지금껏 저질러 왔던 죄는 사라지지 않아.","JPN":"世界を元に戻したところで、君が今まで犯してきた罪が消えるわけではない。","ENG":"Even if you rewind the world, the sins you've committed won't just vanish.","TWN":"即使世界恢復正常，你至今所犯下的罪行也不會消失。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하물며 성공한다고 하더라도, 자네는 지금처럼 어떤 세계에도 속하지 못하게 되겠지.","JPN":"それに成功したとしても、君は今のようにどの世界にも属せなくなるだろう。","ENG":"Even if you succeed, you'll no longer belong to any world.","TWN":"即便成功了，你也將像現在一樣，不屬於任何一個世界。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 자네는 자네가 만들어낸 세계에서도 외톨이로 남게 될 거야.","JPN":"結局、君は君自身が作り出した世界でも一人ぼっちになるんだ。","ENG":"In the end, even in the world you create, you'll be all alone.","TWN":"最終，你在自己創造的世界中也會成為孤獨者。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"누구에게도 이해받지 못한 채, 누구와도 인연을 맺지 못한 채, 미지의 존재로 남을 거라고!","JPN":"誰からも理解されず、誰かと縁を結ぶこともできず、未知の存在としてただ残されるだけだ！","ENG":"No one will understand you. No one will be connected to you. You'll remain as an unknown to everyone!","TWN":"沒有人理解你，也沒有人與你結緣，你將永遠是個未知的存在！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아이린, 자네가 바라는 세계가 진정 그런 세계인가……?","JPN":"アイリーン、君が望む世界とは、真にそのような世界なのかね……？","ENG":"Is that truly the kind of world you want, Irene...?","TWN":"愛琳，你所期望的世界真的是那樣的世界嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"정녕, 영원히 고독한 존재로 남길 바라는 건가……!","JPN":"本当に、永遠の時を孤独な存在として残ってもいいと言うのか……！","ENG":"Do you really want to remain a lonely existence forever...?!","TWN":"真的希望永遠成為孤獨的存在嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"겉모습은 그럴싸하게 만들어 졌지만, 결국에는 내 기억 속 미련일 뿐인가…….","JPN":"見た目はそれっぽくても、所詮は私の記憶の中の未練でしかないわけね……","ENG":"I suppose this was all just lingering regret in my memory...","TWN":"外表看似一樣，但最終不過是我記憶中的執念而已……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"고독한 존재라고요? 얼마든지요, 애버라인.","JPN":"孤独な存在ですか？　望むところです、アバーライン。","ENG":"A lonely existence? I welcome it, Abberline.","TWN":"孤獨的存在嗎？當然了，艾伯林。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초부터 당신을 떠나보낸 뒤로 저는 줄곧 외톨이였답니다.","JPN":"そもそもあなたに先立たれて以来、私はずっと一人ぼっちでした。","ENG":"Ever since I let you go, I've been alone anyway.","TWN":"自從你離開後，我一直都是孤身一人。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신과 이 세계를 되돌리기 위해서라면, 저는 얼마든지 외톨이로 남을 수 있어요.","JPN":"あなたとこの世界を取り戻すためなら、私はいくらでも一人になりましょう。","ENG":"If it means bringing you and this world back, I'll gladly stay that way.","TWN":"只要你和這個世界能後重回過去，我可以一直孤獨下去。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"What are you talking about...?","TWN":"那是什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 이렇게 먼발치에서 당신을 지켜보는 것으로도 충분해요.","JPN":"私はこうして、ただ遠くからあなたを見守るだけで十分です。","ENG":"Just watching you from afar is enough for me.","TWN":"我能在遠處這樣看著你就足夠了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신만큼은 언제 어디서나 아름답고 우아한 백조로 남길 바라니까요.","JPN":"あなただけは、いつまでも美しく優雅な白鳥でいて欲しいから。","ENG":"I want you to always remain a beautiful, graceful swan, no matter where you are.","TWN":"我希望無論何時何地，你都能像優雅的天鵝一樣美麗。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 이제 와서 당신의 손을 잡기에는, 제 손이 너무나 더러워져 버렸으니까요.","JPN":"どのみち、今更あなたの手を取るには、私の手は汚れきってしまった。","ENG":"Besides, my hands are far too tainted now to ever hold yours again.","TWN":"我的手已經太髒了，已經不配再與你攜手了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L38_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 늘 수수께끼 풀이가 업이라고 했죠?","JPN":"あなたはいつも謎解きが仕事だと言いましたよね？","ENG":"You always said solving riddles was your profession, didn't you?","TWN":"你總是說解謎是你的工作，對吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 다시 만날 그 세계에서는 제가 당신의 수수께끼, 그 자체가 되어드리죠.","JPN":"でしたらまた会うその世界では、私があなたの謎そのものになってさしあげましょう。","ENG":"Then in the world we meet again, I'll be your greatest mystery.","TWN":"那麼在我們再次相遇的那個世界裡，我將成為你的謎題本身。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"언젠가 당신과 만났던 미지의 존재, 존 스미스처럼.","JPN":"かつてあなたと出会った未知なる存在、ジョン・スミスのように。","ENG":"Just like John Smith, the unknown figure you once met...","TWN":"就如同某天與你相遇的未知存在約翰·史密斯一樣。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"존 스미스라고……?","JPN":"ジョン・スミスだと……？","ENG":"John Smith...?","TWN":"約翰·史密斯？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아이린, 자네가 그걸 어떻게……?","JPN":"アイリーン、どうして君がその名を……？","ENG":"Irene, how do you know that name...?","TWN":"愛琳，你怎麼會知道？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"한심해요……!","JPN":"情けない……！","ENG":"You're pathetic...!","TWN":"真是無可救藥！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지! 한심하다고요, 미래의 저……!","JPN":"本当に情けないです！　未来の私……！","ENG":"Seriously! You're pathetic, future me...!","TWN":"未來的我是真的讓人無語！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"And you are...?","TWN":"你是？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신에게 무슨 일이 있었는지는 모르겠지만, 저는 정말로 한심한 여자로 커버렸군요……!","JPN":"あなたに何があったのかは知りませんが、私はどうしようもなく情けない女になってしまったんですね……！","ENG":"I don't know what happened to you, but I turned out to be such a pitiful woman...!","TWN":"我不知道你經歷了什麼？但看來我真的變成了一個可悲的女人！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이래서야 스완이라는 이름이 아깝다고요!","JPN":"これではスワンの名が泣きます！","ENG":"The name Swan doesn't even suit you anymore!","TWN":"這樣的話，叫史旺這個名字就太可惜了！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"인정하기는 싫지만, 이미 당신도 알고 있잖아요?","JPN":"認めたくはありませんが、もうあなたもご存じでしょう？","ENG":"You don't want to admit it, but you know it's true, don't you?","TWN":"雖然不想承認，但你已經知道了吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저 남자, 애버라인은 누구보다도 공공의 이익을 우선시하는 사람이에요!","JPN":"あの男、アバーラインは誰よりも公共の利益を優先させる人です！","ENG":"That man, Abberline, is someone who always puts public interest above all else!","TWN":"那個男人，艾伯林是一個比任何人都優先考慮公共利益的人！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"상관도 없는 타인을 위해, 오지랖을 부리다가 침식병까지 걸려버린 멍청한 남자라고요……!","JPN":"関係のない他人のために、お節介を焼いて侵食病にまでなったバカみたいな男なんです……！","ENG":"He's a foolish man who got the Corruption Syndrome just trying to help people he didn't even know...!","TWN":"為了不相干的人多管閒事，結果還感染了侵蝕病的愚蠢男人！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런 사람한테… 지금 대체 무슨 말을 하고 있는 건가요……!","JPN":"そんな彼に向って……いったい今、何を言っているのですか……！","ENG":"Just why... Why are you talking to him like that...?!","TWN":"對那種人……你現在到底在說什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자기를 살리기 위해, 다른 사람들을 희생시키겠다고요?","JPN":"自身を助けるために、他の人たちを犠牲にする？","ENG":"And yet, you're saying you'll sacrifice others to save him?","TWN":"為了拯救自己，就要犧牲其他人嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런 말을 들으면, 저 남자가 정말로 기뻐할 것 같아요?","JPN":"そんなこと言われて、あの男が本心から喜ぶと思いますか？","ENG":"Do you think he'd be happy to hear that?","TWN":"聽到這樣的話，他會真的高興嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"알고 있을 텐데요? 그렇게 되돌려진 삶을 살아봤자, 저 남자에게는 저주나 다름없다는걸!","JPN":"知っているでしょう？　そうして戻した命を与えられたところで、あの男には呪い同然だということを！","ENG":"You know it, don't you? That kind of life would be a curse to him!","TWN":"你應該知道吧？即使過上那樣被逆轉的生活，對那個男人來說也無異於詛咒！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 이건 그 남자와 관계없어요.","JPN":"いいえ。これはあの男とは関係ありません。","ENG":"No. This has nothing to do with him.","TWN":"不，這和那個男人無關。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 원하는 거예요. 이게 제 바람이고, 제 선택이에요.","JPN":"私が欲しているのです。これが私の望みで、私の選択です。","ENG":"This is about what I want. My wish. My choice.","TWN":"這是我想要的。這是我的願望，也是我的選擇。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오래전부터 이것을 이루기 위해서라면, 어떤 악역이든 받아들이겠다고 다짐했으니까.","JPN":"それを叶えるためなら、どんな悪役でも喜んで引き受けると決めたのですから。","ENG":"I swore long ago that I'd play the villain if that's what it took to make this happen.","TWN":"因為很久以前我就下定決心，為了實現這個目標，無論什麼？派角色我都願意接受。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 웃기지 말라고요! 당신……!","JPN":"もう、話にならないわ……！","ENG":"So don't make me laugh! You...!","TWN":"所以別說笑了！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 그렇게 여린 마음을 속여가며 연기해 봤자, 제 눈은 못 속인다고요!","JPN":"そうやって脆い心を隠して演じきったつもりかは知りませんが、私の目は誤魔化せません！","ENG":"Even if you deceive your gentle heart and act, I can see right through you!","TWN":"無論你如何偽裝那顆柔軟的心，也騙不了我的眼睛！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사실은 모두에게 사랑받고 싶은 주제에……! 사실은 악역 같은 건 맡고 싶지 않은 주제에……!","JPN":"本当はみんなに愛されたいくせに……！　本当は悪役なんかやりたくないくせに……！","ENG":"You just want to be loved...! You don't want to play the villain...!","TWN":"你其實是想被大家喜愛的……！其實是不想扮演反派角色的……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사실은 외톨이 같은 건 되고 싶지 않은 주제에……!!","JPN":"本当は一人ぼっちになんて、なりたくないくせに……！！","ENG":"You don't want to be alone...!","TWN":"你其實並不想成為一個孤獨的人……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"사실은 저 남자를 동경하고… 한편으로는 따라잡고 싶다고 생각했던 주제에……!!","JPN":"本当はあの男に憧れて……一方では追いつきたいと思っていたくせに……！！","ENG":"You admire that man... And deep down, you wanted to stand beside him...!!","TWN":"你其實一直仰慕著那個男人……同時也想要追上他……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자기 손이 더러워졌으니까, 먼발치에서 지켜보기만 하겠다고요?","JPN":"自分の手が汚れたから、遠くでただ見守るだけ？","ENG":"But you said your hands were too tainted, so you'd just watch from afar?","TWN":"因為自己的手髒了，就只想在遠處靜靜的看著嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"웃기지 마세요! 당신의 말은 하나부터 열까지 전부 거짓말뿐이잖아……!","JPN":"ふざけないで！　あなたの言ってることは、どれもこれも嘘ばっかり……！","ENG":"Give me a break! Every word out of your mouth is a lie...!","TWN":"別開玩笑了！你說的話從頭到尾全都是謊言……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……큿.","JPN":"……くっ。","ENG":"...Kgh.","TWN":"……哼。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무례하군요, 거기까지 하세요. 무명 시절의 저.","JPN":"無礼ですね。そこまでにしておきなさい、無名時代の私。","ENG":"How rude. That's enough out of you, me from the past.","TWN":"真是無禮，就到此為止吧。無名時期的我。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"시끄럽다고요! 미래의 저……!","JPN":"うるさいです！　未来の私……！","ENG":"Silence! Future me...!","TWN":"你吵死了！未來的我……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"세계를 되돌리겠다고요? 그렇게 과거에 집착한다고 해서 뭐가 달라지죠?","JPN":"世界を元に戻す？　そうやって過去に執着したところで何が変わるんですか？","ENG":"Rewind the world? What good is clinging to the past going to do?","TWN":"要把世界恢復原狀嗎？就算那麼執著於過去，又能改變什麼？？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 진짜 저라면 기억하고 있겠죠? 스스로 이름 붙인 스완이라는 예명의 의미를……!","JPN":"あなたが本当に私なら、覚えているはずです。自分で付けたスワンという芸名の意味を……！","ENG":"If you're really me, then you should remember why I chose the name Swan...!","TWN":"如果你真的是我的話，就應該記得我自己取的藝名史旺的意義！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그건 각오였어요.","JPN":"それは覚悟でした。","ENG":"It was a vow.","TWN":"那是我的決心。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"밀라노 극장을 떠나며 과거를 잊고, 런던이라는 새로운 무대에 서기 위한 각오였다고요……!","JPN":"ミラノの劇場を後にして過去を忘れ、ロンドンという新しい舞台に立つための覚悟……！","ENG":"A vow to leave Milan Theater behind and step onto the new stage of London...!","TWN":"離開米蘭劇院，忘卻過去，決心在倫敦這個新舞台上展現自我！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런데 참 이상하죠? 당신은 지금 또다시 과거로 도망치려 하고 있네요?","JPN":"なのにおかしいですね？　あなたは今、またしても過去に逃げようとしている。","ENG":"But it's strange, right? You're trying to run back to the past again.","TWN":"不過真奇怪啊？你現在又想逃回過去了嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"분명, 당신도 알고 있을 텐데요? 도망치는 것만으로는 아무것도 바꿀 수 없다는 것쯤은……!","JPN":"あなたもわかっているはずです。　逃げるだけでは何も変えられないってことくらい……！","ENG":"You know as well as I do... that running away can't change anything...!","TWN":"你肯定也知道吧？光是逃避是無法改變任何事情的！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 아니라면, 설마 지난 날의 과오를 잊으셨다고 할 셈인가요?","JPN":"まさか過去の過ちを忘れたとでも言うのですか？","ENG":"Or are you planning to say you've forgotten your past mistakes?","TWN":"不然的話，難道你是想說你已經忘記了過去的過錯嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럴 리 없겠죠! 어차피 당신은 그 어떤 것도 망각할 수 없는 여자니까요……!","JPN":"そんなはずありませんよね！　所詮あなたは、何一つ忘れることのできない女ですから……！","ENG":"There's no way. You're not the kind of woman who can forget anything...!","TWN":"那是不可能的！因為你是個無法忘記任何事情的女人……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 나중에 후회하지 말고, 적어도 마지막에는 솔직하게 본심을 전하라고요……!","JPN":"ならば後になって後悔などせず、せめて最後くらい素直な気持ちを伝えてみなさいよ……！","ENG":"Then don't regret it later. At the very least, be honest with yourself at the end...!","TWN":"那你至少在最後坦誠地表達自己的真心，別再做後悔的事了！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제가 당신이라면……!","JPN":"私があなただったら……！","ENG":"If I were you...!","TWN":"如果我是你的話！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"꺄아악……!!","JPN":"きゃああっ……！！","ENG":"Kyaaaah...!!","TWN":"呃啊啊！？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 닥치라고 했을 텐데요? 무명 시절의 저……!","JPN":"黙れと言ったのが聞こえませんでしたか？　無名時代の私……！","ENG":"I said shut up, didn't I? You pathetic, nameless version of me...!","TWN":"我應該讓你閉嘴了吧？無名時期的我！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무리 허상이라고 해도, 감히 제 주제도 모르고 지껄여 대는군요……!","JPN":"いくら虚像とはいえ、身の程も知らないでよく喋りますね……！","ENG":"Even if you're just a shadow, how dare you run your mouth like that...!","TWN":"區區幻影，也敢不自量力地胡言亂語！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 괜찮아!? 꼬마 스완!?","JPN":"ちょっと、大丈夫！？　チビスワン！！","ENG":"Hey, are you okay?! Kid Swan?!","TWN":"喂，你沒事吧！？小史旺！？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"크윽, 누가 꼬마라는 거예요……!","JPN":"くっ、誰がチビですか……！","ENG":"Grrk...! Who are you calling a kid...?!","TWN":"呃，誰說我小的！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후회하지 말라고요……?","JPN":"後悔せずに、と言いましたか……？","ENG":"Don't regret it...?","TWN":"……不要後悔嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초에 제가 유일하게 후회하는 건... 무력했던 무명 시절의 저, 바로 당신이에요……!","JPN":"そもそも私が唯一後悔しているのは……無力だった無名時代の私、そう、あなたです……！","ENG":"The only thing I regret... is the helpless and unknown me. You...!","TWN":"最初我唯一後悔的就是……無能的無名時期的我，也就是你！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어울리지도 않는 거창한 배역을 맡은 주제에, 아무것도 모르고 또 알려고 노력하지도 않죠.","JPN":"身に余る大役を任されておいて、何も知らず、また知ろうともしない。","ENG":"You took on a grand role that didn't suit you, and yet you knew nothing. Didn't even try to understand.","TWN":"明明擔任了不合適的大角色，卻什麼也不知道，也不努力去瞭解。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 알고 있을 텐데요, 무지는 죄랍니다.","JPN":"あなたもわかっているはずです、無知は罪だと。","ENG":"You know, don't you? Ignorance is a sin.","TWN":"你應該也知道，無知也是一種罪過。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 더 빨리 모든 걸 눈치채고, 더 빨리 모두와 만났다면, 더 많은 걸 바꿀 수 있었겠죠.","JPN":"あなたがもっと早く全てに気づき、もっと早くみんなと出会えていれば、もっとたくさんのことを変えられた。","ENG":"If you'd realized everything sooner, if you'd met everyone earlier, so much could've changed.","TWN":"如果你能更早察覺到一切，並更早與大家見面，或許能改變更多事情。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"만약, 그렇다면 우리 세계는 다른 결말을 맞이할 수도 있었어요……!","JPN":"もしそうだったら、私たちの世界は違う結末を向かえたかもしれない……！","ENG":"Had that been the case, our world might have seen a different conclusion…!","TWN":"如果是那樣的話，我們的世界可能會迎來不同的結局！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아이린……?","JPN":"アイリーン……？","ENG":"Irene...?","TWN":"愛琳？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면, 자네 설마……?","JPN":"もしかして、君は……？","ENG":"Wait, you're not...","TWN":"也許，你難道……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요, 때 마침 시작되었군요.","JPN":"いいでしょう、ちょうど始まりました。","ENG":"Perfect timing. It's beginning.","TWN":"好吧，正好開始了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국, 모든 것은 각본대로…….","JPN":"結局、すべては脚本どおりに……","ENG":"In the end, everything according to the script...","TWN":"最終，一切都將按照劇本進行……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금 이 순간이 지금까지 준비해 온 각본의 마지막 엔딩이랍니다.","JPN":"今この瞬間が、今まで準備してきた脚本の最後のエンディングです。","ENG":"This moment marks the final ending of the story I've prepared.","TWN":"此刻就是我一直以來準備的劇本的最終結局。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"동시에 세계의 끝을 너머, 모든 이야기를 처음으로 되돌리는 시작점이라고도 할 수 있겠죠.","JPN":"そして同時に世界の終わりを超えて、全ての物語を振り出しに戻すスタート地点とも言えるでしょう。","ENG":"And at the same time, the start of something new. The beginning of reverting all the stories to their beginning.","TWN":"同時也可以說是超越世界盡頭，將所有故事回到起點的開始。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐지? 갑자기 지하 신전에 지진이……!?","JPN":"何？　急に地下神殿に地震が……！？","ENG":"What's happening? An earthquake in the underground temple...?!","TWN":"怎麼回事？地下神殿突然地震了？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이건 단순한 지진이 아니야. 공간 자체에 균열이 발생하고 있어.","JPN":"これはただの地震じゃない。空間そのものに亀裂が入ってる。","ENG":"This isn't just an earthquake. The very fabric of space is starting to crack.","TWN":"這不僅僅是地震。空間本身正在出現裂縫。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"역시 세계가 멸망하는 순간이라는 건… 이런 뜻이었나……?","JPN":"世界が滅亡する瞬間って、やっぱりこういう意味だったの……？","ENG":"So this is what she meant... by the moment the world ends...?","TWN":"果然，世界毀滅的瞬間……是這個意思嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 설마……!?","JPN":"じゃ、じゃあまさか……！？","ENG":"Wait! Then...","TWN":"那麼，難道！？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하, 하하. 그동안 무수한 사건을 해결해왔는데…….","JPN":"は、はは……今まで数々の事件を解決してきたが……","ENG":"Ha, haha. After solving so many cases...","TWN":"哈——哈哈。我曾解決了無數的案件……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그 결과가 애석하게도 이거로군.","JPN":"残念なことにその結果がこれか。","ENG":"To end up with this result. What a shame.","TWN":"結果竟然是這樣，真是遺憾。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 우리 세계는 결국 이런 식으로 멸망했던 건가…….","JPN":"やはり私たちの世界は、このようにして滅亡したのだな……","ENG":"So our world really did end like this...","TWN":"果然，我們的世界最終還是以這種方式毀滅了嗎……？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자, 잠깐! 저 괴물은 대체……?","JPN":"ま、待って！　あの化け物はいったい……？","ENG":"W-wait! What is that monster...?!","TWN":"等一下！怪物到底是……？"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인! 무언가가 밤 하늘을 찢고 나타나고 있어요……!","JPN":"アバーライン！　夜空を引き裂くように、何かが現れています……！","ENG":"Abberline! Something's tearing through the night sky!","TWN":"艾伯林！有東西正在撕裂夜空！"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모두들 듣게! 지금 즉시 이 자리에서 전원 이탈하도록……!","JPN":"全員聞きたまえ！　ただちにこの場から離れろ……！","ENG":"Everyone, listen! Leave this place immediately...!","TWN":"大家聽著！立刻從這裡撤離！"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"저건 인간이 어쩔 수 있는 상대가 아니야……!","JPN":"あれは人間がどうこうできる相手ではない……！","ENG":"That thing isn't something humans can fight...!","TWN":"那不是人類能夠對付的對手！"},"stage":{"bg":"SWANSONG_03","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건… 허신인가……?","JPN":"あれは……虚神……？","ENG":"Is that... a Hollow God...?","TWN":"那是……虛神嗎……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 저 망할 년! 결국 불러들이고 말았나……!","JPN":"あの、クソ女！　呼び寄せちまったのかよ……！","ENG":"Tch, that damned woman! She really summoned it...?!","TWN":"嘖，那該死的女人！？終還是把她召喚過來了……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"싸워야 돼, 에이미.","JPN":"戦うしかない、エイミー。","ENG":"We have to fight, Amy.","TWN":"必須戰鬥，艾米。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기서 저걸 상대할 수 있는 사람은 우리 밖에 없어.","JPN":"ここであれの相手ができるのは、私たちしかいない。","ENG":"No one else here can face that thing but us.","TWN":"在這裡能對付那個東西的只有我們。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"딱 한 번뿐이지만…… 허신이라면 쓰러트려 본 적 있어.","JPN":"一度だけだけど……虚神なら、前に倒したことがある。","ENG":"Even if it's only once... I've taken down a Hollow God before.","TWN":"雖然只有一次……但我曾經打倒過虛神。"},"stage":{"bg":"MAINSTREAM_805","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그때는 대령 아저씨가 허신의 몸체를 날려줘서, 녀석의 심장을 노릴 수 있었거든.","JPN":"その時は大佐が虚神の身体を飛ばしてくれて、やつの心臓を狙えた。","ENG":"Back then, the Colonel blasted its body open so I could go for the heart.","TWN":"那時候是上校大叔把虛神的身體打飛了，我才能瞄準它的心臟。"},"stage":{"bg":"MAINSTREAM_805","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그때랑 상황이 다르긴 하지만, 울브즈베인이 통한다면 허신을 쓰러트릴 수 있을지도 몰라.","JPN":"状況は違うけど、ウルブズベインが通じるなら虚神を倒せるかもしれない。","ENG":"Things are different now, but if Wolvesbane still works, we might be able to bring it down.","TWN":"雖然情況和那時不同，但如果能用狼之災禍，也許可以打倒虛神。"},"stage":{"bg":"MAINSTREAM_805","bgm":"THEMA_EXCUTE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그러니까 네 말은… 지금 나보고 그 망할 대령 역할을 대신해달라는 거야……?","JPN":"つまり……今あたしにあのクソ大佐の代わりになれってこと……？","ENG":"So... you want me to play the role of that damned Colonel now...?","TWN":"所以你的意思是……現在讓我去替代那個該死的上校角色？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 날 너무 과대평가하고 있는 거 아니야? 그 대령 녀석은 상정 외의 괴물이잖아.","JPN":"いやいや、あたしのこと買いかぶり過ぎじゃない？　あの大佐は想定外の化け物でしょ。","ENG":"Don't you think you're overestimating me a bit? That guy was a freak of nature.","TWN":"你不覺得你有點高估我了嗎？那傢伙可是天生異稟。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야? 너 대령 아저씨를 알아?","JPN":"ん？　あなた、大佐を知っているの？","ENG":"Wait, you know Colonel?","TWN":"什麼？你認識上校大叔？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"알다마다 그 재수 없는 망할 자식, 어떻게 잊어버리겠어?","JPN":"知っているも何も。あのいけ好かない野郎、忘れる方が難しいよ。","ENG":"Know that infuriating bastard? How could I forget?","TWN":"怎麼可能忘記那個討厭的混蛋？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어쨌든 네가 코어를 노린다고 해도, 나 혼자 허신의 공격을 전부 막아내는 건 무리야.","JPN":"とにかく、あんたがコアを狙うにしても、あたし一人で虚神の攻撃を全部防ぐのは無理。","ENG":"Anyway, even if you go for the core, I can't hold off all attacks of that thing alone.","TWN":"就算你能瞄準核心，我一個人也無法擋住虛神的所有攻擊。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"적어도 잠깐이라도 녀석을 땅으로 떨어트린 뒤에 움직임을 봉쇄해야 해.","JPN":"せめて一瞬でもあいつを地面に落として、動きを止めなきゃ。","ENG":"We'll need to bring it down to the ground and stop its movements, even just for a moment.","TWN":"至少要暫時把那傢伙打落到地面，然後封鎖其行動。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그게 아니라면…….","JPN":"じゃなかったら……","ENG":"If we don't...","TWN":"或者說……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저길 봐…! 녀석이 완전히 공간을 찢고 나왔어……!","JPN":"見て、あれ……！　やつが空間を完全に切り裂いて出てきた……！","ENG":"Look...! It's completely torn through the space...!","TWN":"看啊……！他已經完全撕裂了空間……！"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고민할 시간이 없어, 에이미. 일단은……","JPN":"悩んでいる時間はないよ、エイミー。とりあえず……","ENG":"There's no time to think, Amy. We need to–","TWN":"沒有時間猶豫了，艾米。你先……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"엇!?","JPN":"あっ！？","ENG":"Huh?!","TWN":"哎！？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"결국, 이 세계에도 도래하고 마는가.","JPN":"結局、この世界にも到来してしまうのか。","ENG":"So... they descend even in this world.","TWN":"最終，這個世界也在劫難逃。"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"종언의 수호자들이.","JPN":"終焉の守護者たちが。","ENG":"The Guardians of Downfall.","TWN":"終焉的守護者們……"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야, 저 검은 갑옷? 방금 허신의 공격을 받아낸 거야……?","JPN":"何、あの黒い鎧？　今、虚神の攻撃を受け止めた……？","ENG":"What is that black armor...? Did it just block the Hollow God's attack...?","TWN":"什麼？那黑色盔甲？剛剛擋住了虛神的攻擊?"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저건 모르스…? 모르스가 왜 여기에……?","JPN":"あれは、モールス……？　モールスがどうしてここに……？","ENG":"Is that Mors...? What's Mors doing here...?","TWN":"那是死神？死神怎麼會在這裡？"},"stage":{"bg":"CORRIDOR_09","bgm":"THEMA_EXCUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"미나 씨…! 여기예요! 여기……!!","JPN":"ミナさん……！　こっちです！　こっち……！！","ENG":"Mina...! Over here! Here...!!","TWN":"米娜！這裡……！這裡……！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐야, 이 녀석들……?","JPN":"なんだ、こいつら……？","ENG":"Huh? They're...?","TWN":"什麼？這些傢伙……？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그럼, 쥐돌이가 말하던 조력자가 유미나였어?","JPN":"ネズミが言っていた協力者ってミナのことだったの？","ENG":"Wait, so the supporter that rat-girl mentioned was Yoo Mina?","TWN":"所以，老鼠說的幫手是劉米娜嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트, 라이카……?","JPN":"フェリセット、ライカ……？","ENG":"Félicette? Laika...?","TWN":"費莉塞特、萊卡？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너희들이 여기는 어쩐 일이야? 게다가 그 모습은 또 뭐고…? 메이드……?","JPN":"あなたたち、ここにはどうやって？　それにその格好は……？　メイド……？","ENG":"What are you two doing here? And what's with those maid outfits...?","TWN":"你們怎麼會在這裡？而且這副模樣是怎麼回事……女僕裝?"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 나 그 메이드 복장 알 것 같아. 회사에서 본 적 있어……!","JPN":"そうだ、そのメイド服、見覚えがあるよ。確か会社で……！","ENG":"Wait a second, I recognize those maid uniforms. I've seen them at the company...!","TWN":"等一下，我好像認得那套女僕裝。在公司見過！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"시끄러워, 자세한 건 묻지 말라고. 쪽팔리니까.","JPN":"うるさいな、いちいち聞かないでよ。恥ずかしいから。","ENG":"Can it! Don't ask. It's embarrassing, all right?","TWN":"吵死了，別問那麼詳細，太丟人了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"잠깐, 저 거대한 침식체는……?","JPN":"それよりも、あの巨大な侵食体は……？","ENG":"Hold on, that giant C.O. is...?","TWN":"等一下，那巨大的侵蝕體是？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"관리국 최고 재난 경보 때 나타났던 제6종 침식체잖아요……?","JPN":"管理局の最高災難警報の時に出てた、第6種侵食体ですよね……？","ENG":"It's a Category 6 C.O. The kind that appeared during the Administration's highest-level disaster alert...!","TWN":"那不是管理局最高災難警報時出現的6類侵蝕體嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"상황이 어떻게 돌아가는 건진 모르겠지만, 우리가 제때 도착한 거겠죠, 라이카?","JPN":"どういう状況かは知らないけど、なんとか間に合ったみたいだね？　ライカ。","ENG":"I don't know exactly what's going on, but it looks like we made it just in time, right, Laika?","TWN":"雖然不知道情況如何，但我們應該及時趕到了，對吧，萊卡？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제때는 개뿔이! 누가 봐도 죽기 딱 좋은 타이밍이잖아……!","JPN":"間に合うだ！？　どこをどう見ても今から死にますってタイミングじゃねぇか……！","ENG":"Just in time? Yeah right! This is the worst timing possible! We're right in the kill zone...!","TWN":"什麼及時！分明是個送死的時機……！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"아무튼 뒈지기 싫으면, 내 뒤에 딱 붙어 있으라고, 꼬맹이!","JPN":"とにかくくたばりたくなかったら、私の後ろにくっついてな、おこちゃま！","ENG":"Anyway, if you don't wanna die, stick close to me, got it, kid?!","TWN":"總之，如果不想死的話，就緊跟在我後面，小鬼！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"저것은 역병의 악취를 쫓아 몰려든 불멸의 존재.","JPN":"あれは疫病の悪臭に群がる不滅の存在。","ENG":"That immortal is drawn here by the stench of plague.","TWN":"那是追隨瘟疫惡臭而來的不滅之物。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"보통의 힘으로는 멸할 수 없으니. 오직 그대가 가진 검으로만 저들을 심판할 수 있으리라.","JPN":"通常の力では滅することもできん。そなたの持つ剣でのみ、奴らを裁くことができよう。","ENG":"Not destroyed through normal means. Only the blade you possess can deliver judgment upon it.","TWN":"普通的力量無法消滅他們。只有用你手中的劍才能審判他們。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"모르스……!","JPN":"モールス……！","ENG":"Mors...!","TWN":"死神！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"다른 세계에서 온 이방인들이여.","JPN":"異世界より来たる異邦人よ。","ENG":"Strangers from another world.","TWN":"來自其他世界的外邦人。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_START_BIG"},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대들이 어떠한 이유로 이곳에 있는지는 알지 못하나, 내가 그대들의 방패가 되겠다.","JPN":"そなたらが如何様な事情でここにいるのかは知らんが、我がそなたらの盾になろう。","ENG":"I do not know why you've come here, but I shall become your shield.","TWN":"雖然我不知道你們為何在此，但我會成為你們的盾牌。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"분명, 그것이 우리가 저것을 쓰러트릴 수 있는 유일한 방법일 터이니…….","JPN":"それが、我らがあれを倒せる唯一の方法であろう……","ENG":"For that may be the only way we have to defeat it...","TWN":"顯然，那是我們能擊敗它的唯一方法……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 이번에도 한발 늦었군요, 모르스. 그리고 카나리아 스쿼드라…….","JPN":"やはり今回も一歩遅かったですね、モールス。それに、カナリア・スクワッド、ですか……","ENG":"So you're late again, Mors. And Canary Squad too...","TWN":"果然這次也晚了一步啊，死神。還有金絲雀小隊……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무래도 당신들과는 참 질긴 인연으로 맺어진 모양이네요.","JPN":"どうやらあなたたちとは、腐れ縁で結ばれているようです。","ENG":"Seems we really are bound by some persistent fate, aren't we?","TWN":"看來我和你們之間的緣分還真是深厚呢。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"설마, 마지막 순간에 절 막아서는 게… 또다시 병든 병아리들과 저 패배자일 줄이야.","JPN":"まさか、最後の最後に私の前に立ちはだかるのが……またもや死にかけのヒヨコたちに、あの敗北者とは。","ENG":"To think that at the very end, the ones trying to stop me again... would be those sickly chicks and that loser.","TWN":"沒想到，在最後一刻擋住我的……竟然又是那些病弱的小雞仔和那個手下敗將。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그 악연도 여기까지겠죠.","JPN":"ですが、その腐れ縁もここまでです。","ENG":"But this cursed bond ends here.","TWN":"不過，這段孽緣也到此為止吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"스완! 무슨 짓을 꾸미는지는 모르겠지만 그만두는 게 좋을 거예요!","JPN":"スワン！　何を企んでいるのかは知りませんが、諦めた方がいいですよ！","ENG":"Swan! I don't know what you're planning, but you'd better stop now!","TWN":"史旺！雖然我不知道你在打什麼主意，但最好還是停手吧！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"당신의 계획이 뭐든간에 반드시 막아낼 테니까!","JPN":"あなたの計画が何であれ、必ず止めてみせるから！","ENG":"Whatever your plan is, we'll stop it no matter what!","TWN":"無論你的計畫是什麼？我一定會阻止你！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어이, 여배우! 너 보기보다 머리가 나쁜 거 아니야?","JPN":"おい、女優！　あんた、思ったよりおつむが足りてないようだな？","ENG":"Hey, actress! Are you really that dense?","TWN":"喂，女演員！你是不是其實很笨啊？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"지난번에도 그렇게 실컷 잘난 척하다가, 요 꼬맹이한테 된통 털렸던 거 벌써 까먹었어?","JPN":"この前だって、そうやって余裕ぶっこいてて、このおこちゃまにボコボコにされたの、もう忘れたのか？","ENG":"Did you already forget how last time you got your smug face kicked in by this kid?","TWN":"上次也是那麼自以為是，結果被這個小鬼狠狠教訓了一頓，已經忘了嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그리고 아마 이번에도 그렇게 될 거야.","JPN":"今回も多分同じだよ。","ENG":"And I've got a feeling it's gonna go down the same way this time too.","TWN":"而且這次可能也會那樣。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"우릴 보낸 보스는 우리가 세계를 바꿀 <color=#ffd34c>변수</color>라고 했으니까.","JPN":"私たちを送り出したボスは、私たちが世界を変える<color=#ffd34c>変数</color>だって言ってたから。","ENG":"Our boss said we're the <color=#ffd34c>variables</color> that'll change the world.","TWN":"派我們來的老闆說我們是能改變世界的<color=#ffd34c>變數</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그게 무슨 개 풀 뜯어먹는 소리인지는 아직도 잘 모르겠지만 말이야.","JPN":"どういう意味かは、まだわかんないけど。","ENG":"I still don't get what that means, but whatever.","TWN":"雖然我還是不太明白那是什麼胡嚴亂語。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"아무튼 변수면 변수답게 깽판이라도 쳐주는 게 예의겠지?","JPN":"何はともあれ変数なら変数らしく、場を乱してやんなきゃだろ？","ENG":"If we're variables, the least we can do is throw this whole place into chaos, right?","TWN":"不管怎樣，既然是變數，就應該像變數一樣搗亂才對吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 세계를 바꿀 변수라…….","JPN":"ふふ、世界を変える変数ですか……","ENG":"Haha, variables that can change the world...","TWN":"呵呵，改變世界的變數嗎？？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"확실히 그럴지도 모르겠군요. 현실에서 저는 당신들의 행방을 놓치고 말았죠.","JPN":"確かにそうかもしれませんね。現実での私は、あなたたちの行方を見失ってしまった。","ENG":"Maybe so. I did lose track of you in the real world.","TWN":"確實可能是這樣。在現實中，我失去了你們的蹤跡。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그런데 설마 저보다 먼저 제 각본을 꿰뚫어 본 사람이 있을 줄이야. 대단하네요, 그 사람은.","JPN":"しかし、まさか私よりも先にこの脚本を見抜いていた人がいたとは。すごいですね、その方。","ENG":"But I never imagined someone could see through my script before I even finished it. That person must be something else.","TWN":"不過，沒想到居然有人比我更早看穿了我的劇本。那個人確實很厲害。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 이제 와서 달라지는 건 아무것도 없을 겁니다.","JPN":"ですが、今更変わることは何もありません。","ENG":"Still, it's far too late to change anything now.","TWN":"但如今再怎麼做也不會有任何改變。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결말에 다다른 각본을 막아서기에는, 당신들은 너무나 작고 미약한 존재니까요.","JPN":"結末に差し掛かった脚本を止めるには、あなたたちはあまりにも小さく微弱な存在ですから。","ENG":"You're too insignificant, too powerless to stop a script already nearing its final act.","TWN":"要想阻止已經走到結局的劇本，你們的力量實在是太渺小。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 무대에서 제가 맡은 역할은 <color=#ffd34c>세계</color>.","JPN":"この舞台で私が演じる役は、<color=#ffd34c>世界</color>。","ENG":"In this grand performance, I play the role of the <color=#ffd34c>World</color>.","TWN":"在這個舞台上，我的角色是<color=#ffd34c>世界</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 의미는 완성과 순환. 그리고 여정의 종결과 새로운 시작…….","JPN":"その意味するところは完成と循環、そして旅路の終わりと新たな始まり……","ENG":"That means completion and recurrence. The end of one journey and the beginning of another...","TWN":"那表示完成與迴圈。以及旅程的結束與新的開始……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 기쁜 마음으로 이 세계에 다다른 모든 이들에게 여정의 종결을 선사하겠습니다.","JPN":"ですので、この世界に至った全ての者に、喜んで旅路の終わりを授けましょう。","ENG":"So I'll graciously offer a fitting conclusion to all those who've reached this world.","TWN":"所以，我將為所有滿懷喜悅來到這個世界的人終結旅程。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마침내 그 모든 이야기를 처음으로 되돌리기 위해서.","JPN":"その全ての物語を振り出しに戻すために。","ENG":"So that at last, to revert all the stories to their beginning.","TWN":"終於可以讓所有的故事回到起點。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};